function setFaviconForTheme(e){const n=e==="dark",s=document.getElementById("favicon-shortcut"),o=document.getElementById("favicon-32"),i=document.getElementById("favicon-16"),t="?v=4";if(!s||!o||!i)return;s.href=n?"/images/favicons/favicon-dark-32.png"+t:"/images/favicons/favicon-light-32.png"+t,o.href=n?"/images/favicons/favicon-dark-32.png"+t:"/images/favicons/favicon-light-32.png"+t,i.href=n?"/images/favicons/favicon-dark-16.png"+t:"/images/favicons/favicon-light-16.png"+t}function getActiveTheme(){const e=document.body;return e.classList.contains("colorscheme-dark")?"dark":e.classList.contains("colorscheme-light")?"light":window.matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light"}document.addEventListener("DOMContentLoaded",function(){setFaviconForTheme(getActiveTheme())}),document.addEventListener("themeChanged",function(){setFaviconForTheme(getActiveTheme())})